					self::$user['org_id'] = $this->User->Organisation->createOrgFromName($org, 0, true);
					unset(self::$user['org']);
				}
				if ($userDefaults && is_array($userDefaults)) {
					self::$user = array_merge(self::$user, $userDefaults);
				}
				$this->User->create();
