      $detail->getFromDB($detailID);
      $license = $detail->fields["items_id"];

      $this->removeInfoComRelatedToOrder($itemtype, $license);
      $result = $PluginOrderOrder_Item->queryRef($detail->fields["plugin_order_orders_id"],
